function createSpinner(text) {
  const frames = ["в†Л", "в†Щ", "в†є", "в†Є", "в†Љ", "в†і", "в†¶", "в†І", "в†З", "в†П"];
  let i = 0;
  if (process.stdout.write) process.stdout.write('\x1b[?25l'); 
  const timer = setInterval(() => {
    if (process.stdout.clearLine) {
        process.stdout.clearLine(0);
        process.stdout.cursorTo(0);
        process.stdout.write(`${colors.cyan}${frames[i]}${colors.reset} ${text}`);
    } else {
        // Fallback for non-TTY
        if (i === 0) console.log(`${colors.cyan}вП≥${colors.reset} ${text}`);
    }
    i = (i + 1) % frames.length;
  }, 80);

  return () => {
    clearInterval(timer);
    if (process.stdout.clearLine) {
        process.stdout.clearLine(0);
        process.stdout.cursorTo(0);
        process.stdout.write('\x1b[?25h');
    }
  };
}
